"use client";

import { useEffect, useState } from "react";
import { Mail, User, ArrowLeft } from "lucide-react";
import { useRouter } from "next/navigation";

const BASE_URL = "http://localhost:5000";

const MyMessagesPage = () => {
  const router = useRouter();

  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);

  // ================= FETCH MESSAGES =================
  useEffect(() => {
    const fetchMessages = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch(`${BASE_URL}/user/myMessage`, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        if (!res.ok) throw new Error("Failed to fetch messages");

        const data = await res.json();
        setMessages(data);
      } catch (err) {
        console.error("Message fetch error:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchMessages();
  }, []);

  // ================= LOADING =================
  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center text-gray-500 animate-pulse">
        Loading your messages...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-10">
      {/* Header */}
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-6 py-4 flex items-center justify-between">
          <button
            onClick={() => router.back()}
            className="flex items-center text-gray-600 hover:text-gray-900 transition"
          >
            <ArrowLeft size={20} className="mr-2" /> Back
          </button>

          <h1 className="text-xl font-bold text-gray-800 flex items-center gap-2">
            <Mail size={20} className="text-blue-600" /> My Messages
          </h1>
        </div>
      </div>

      {/* Message List */}
      <main className="max-w-5xl mx-auto px-6 mt-6">
        {messages.length === 0 ? (
          <div className="bg-white rounded-xl border p-10 text-center text-gray-500">
            No messages yet 📭
          </div>
        ) : (
          <div className="space-y-4">
            {messages.map((msg) => (
              <div
                key={msg._id}
                className="bg-white border rounded-2xl p-5 shadow-sm hover:shadow-md transition"
              >
                <div className="flex items-start justify-between gap-4">
                  {/* Sender */}
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-blue-100 text-blue-700 flex items-center justify-center font-bold">
                      {msg.sender?.name?.charAt(0) || "A"}
                    </div>
                    <div>
                      <p className="font-semibold text-gray-800">
                        {msg.sender?.name || "Admin"}
                      </p>
                      <p className="text-xs text-gray-500">
                        {msg.sender?.email || "system"}
                      </p>
                    </div>
                  </div>

                  {/* Date */}
                  <p className="text-xs text-gray-400 whitespace-nowrap">
                    {new Date(msg.createdAt).toLocaleString()}
                  </p>
                </div>

                {/* Message Body */}
                <div className="mt-4 bg-gray-50 border rounded-xl p-4 text-gray-700 text-sm leading-relaxed">
                  {msg.message}
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

export default MyMessagesPage;
